package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.util.Objects;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void setFieldNamingStrategy_NullStrategy_ThrowsNullPointerException() {
    NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
      gsonBuilder.setFieldNamingStrategy(null);
    });
    assertNotNull(thrown);
  }

  @Test
  void setFieldNamingStrategy_ValidStrategy_UpdatesFieldAndReturnsThis() throws Exception {
    FieldNamingStrategy mockStrategy = mock(FieldNamingStrategy.class);
    GsonBuilder returned = gsonBuilder.setFieldNamingStrategy(mockStrategy);
    assertSame(gsonBuilder, returned);

    // Use reflection to verify the private field fieldNamingPolicy was updated
    Field field = GsonBuilder.class.getDeclaredField("fieldNamingPolicy");
    field.setAccessible(true);
    Object fieldValue = field.get(gsonBuilder);
    assertSame(mockStrategy, fieldValue);
  }

  @Test
  void setFieldNamingStrategy_IdentityStrategy_ReplacesDefault() throws Exception {
    // Default is FieldNamingPolicy.IDENTITY, verify initial state
    Field field = GsonBuilder.class.getDeclaredField("fieldNamingPolicy");
    field.setAccessible(true);
    Object initialValue = field.get(gsonBuilder);
    assertSame(FieldNamingPolicy.IDENTITY, initialValue);

    // Set new strategy
    FieldNamingStrategy newStrategy = mock(FieldNamingStrategy.class);
    gsonBuilder.setFieldNamingStrategy(newStrategy);

    // Verify field updated
    Object updatedValue = field.get(gsonBuilder);
    assertSame(newStrategy, updatedValue);
  }
}
